class Solution {
    // Recursive helper to generate subsets
    findSubsets(index, nums, current, ansSet) {
        if (index === nums.length) {
            // Use JSON string as unique key for current subset (arrays not hashable)
            ansSet.add(JSON.stringify(current));
            return;
        }

        // Include current element
        current.push(nums[index]);
        this.findSubsets(index + 1, nums, current, ansSet);
        current.pop();

        // Exclude current element
        this.findSubsets(index + 1, nums, current, ansSet);
    }

    subsetsWithDup(nums) {
        const ansSet = new Set();
        const current = [];

        // Sort the input array to handle duplicates properly
        nums.sort((a, b) => a - b);

        this.findSubsets(0, nums, current, ansSet);

        // Convert set of JSON strings back to arrays
        return [...ansSet].map(str => JSON.parse(str));
    }
}

